import{_ as e,o as r,c as a,a7 as n}from"./chunks/framework.BgApuQ2e.js";const o="/images/the-great-perils-of-social-interaction/hello.png",i="/images/the-great-perils-of-social-interaction/handshake.png",s="/images/the-great-perils-of-social-interaction/handshake-2.png",p="/images/the-great-perils-of-social-interaction/handshake-3.png",g="/images/the-great-perils-of-social-interaction/kiss1.png",l="/images/the-great-perils-of-social-interaction/adjacent-embrace-1.png",c="/images/the-great-perils-of-social-interaction/adjacent-embrace-2.png",h="/images/the-great-perils-of-social-interaction/adjacent-embrace-3.png",m="/images/the-great-perils-of-social-interaction/adjacent-embrace-4.png",w="/images/the-great-perils-of-social-interaction/adjacent-embrace-5.png",b="/images/the-great-perils-of-social-interaction/adjacent-embrace-6.png",f="/images/the-great-perils-of-social-interaction/restaurant-1.png",_="/images/the-great-perils-of-social-interaction/restaurant-2.png",u="/images/the-great-perils-of-social-interaction/restaurant-31.png",d="/images/the-great-perils-of-social-interaction/restaurant-4.png",k="/images/the-great-perils-of-social-interaction/restaurant-51.png",y="/images/the-great-perils-of-social-interaction/restaurant-6.png",z="/images/the-great-perils-of-social-interaction/restaurant-7.png",S="/images/the-great-perils-of-social-interaction/tic-tacs.png",A="/images/the-great-perils-of-social-interaction/tic-tacs-2.png",j="/images/the-great-perils-of-social-interaction/Acquaintance-graph.png",q="/images/the-great-perils-of-social-interaction/doors.png",I="/images/the-great-perils-of-social-interaction/work-0.png",P="/images/the-great-perils-of-social-interaction/work-1.png",T="/images/the-great-perils-of-social-interaction/work-2.png",F="/images/the-great-perils-of-social-interaction/work-3.png",x="/images/the-great-perils-of-social-interaction/work-4.png",W="/images/the-great-perils-of-social-interaction/WhatsUp.jpg",G="/images/the-great-perils-of-social-interaction/run-in-1.png",U="/images/the-great-perils-of-social-interaction/run-in-2.png",v="/images/the-great-perils-of-social-interaction/run-in-3.png",H="/images/the-great-perils-of-social-interaction/run-in-4.png",R="/images/the-great-perils-of-social-interaction/run-in-4.5.png",B="/images/the-great-perils-of-social-interaction/run-in-5.png",D="/images/the-great-perils-of-social-interaction/run-in-6.png",M="/images/the-great-perils-of-social-interaction/see-meet.jpg",N="/images/the-great-perils-of-social-interaction/walking-direction-1.png",$="/images/the-great-perils-of-social-interaction/walking-direction-2.png",E="/images/the-great-perils-of-social-interaction/walking-direction-3.png",V="/images/the-great-perils-of-social-interaction/walking-direction-4.png",C="/images/the-great-perils-of-social-interaction/walking-direction-5.png",O="/images/the-great-perils-of-social-interaction/walking-direction-6.png",Z="/images/the-great-perils-of-social-interaction/walking-direction-7.png",J="/images/the-great-perils-of-social-interaction/walking-direction-8.png",K="/images/the-great-perils-of-social-interaction/walking-direction-9.png",Y="/images/the-great-perils-of-social-interaction/sneeze-1.png",L="/images/the-great-perils-of-social-interaction/sneeze-2.png",Q="/images/the-great-perils-of-social-interaction/sneeze-3.png",X="/images/the-great-perils-of-social-interaction/sneeze-4.png",tt="/images/the-great-perils-of-social-interaction/sneeze-5.png",et="/images/the-great-perils-of-social-interaction/sneeze-6.png",rt="/images/the-great-perils-of-social-interaction/sneeze-7.png",at="/images/the-great-perils-of-social-interaction/sneeze-8.png",nt="/images/the-great-perils-of-social-interaction/sneeze-9.png",ot="/images/the-great-perils-of-social-interaction/sneeze-10.png",it="/images/the-great-perils-of-social-interaction/sneeze-11.png",st="/images/the-great-perils-of-social-interaction/sneeze-12.png",pt="/images/the-great-perils-of-social-interaction/sneeze-13.png",gt="/images/the-great-perils-of-social-interaction/sneeze-14.png",lt="/images/the-great-perils-of-social-interaction/urinal-1.png",ct="/images/the-great-perils-of-social-interaction/urinal-2.png",ht="/images/the-great-perils-of-social-interaction/urinal-3.png",mt="/images/the-great-perils-of-social-interaction/urinal-4.png",wt="/images/the-great-perils-of-social-interaction/urinal-b-1.png",bt="/images/the-great-perils-of-social-interaction/urinal-b-2.png",ft="/images/the-great-perils-of-social-interaction/baby-1.png",_t="/images/the-great-perils-of-social-interaction/baby-2.png",ut="/images/the-great-perils-of-social-interaction/baby-3.png",dt="/images/the-great-perils-of-social-interaction/baby-4.png",kt="/images/the-great-perils-of-social-interaction/baby-5.png",yt="/images/the-great-perils-of-social-interaction/baby-6.png",zt="/images/the-great-perils-of-social-interaction/baby-7.png",St="/images/the-great-perils-of-social-interaction/baby-8.png",At="/images/the-great-perils-of-social-interaction/baby-9.png",jt="/images/the-great-perils-of-social-interaction/goodbye.png",qt="/images/the-great-perils-of-social-interaction/goodbye-2.png",It="/images/the-great-perils-of-social-interaction/goodbye-3.png",Pt="/images/the-great-perils-of-social-interaction/pinit_fg_en_rect_gray_20.png",Rt=JSON.parse('{"title":"The Great Perils of Social Interaction","description":"","frontmatter":{"title":"The Great Perils of Social Interaction","titleZh":"社交互动的巨大风险","date":"2014-01-21T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/01/the-great-perils-of-social-interaction.html","slug":"the-great-perils-of-social-interaction"},"headers":[],"relativePath":"posts/the-great-perils-of-social-interaction.md","filePath":"posts/the-great-perils-of-social-interaction.md","lastUpdated":1782886257000}'),Tt={name:"posts/the-great-perils-of-social-interaction.md"};function Ft(xt,t,Wt,Gt,Ut,vt){return r(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="社交互动的巨大风险-·-the-great-perils-of-social-interaction" tabindex="-1">社交互动的巨大风险 · The Great Perils of Social Interaction <a class="header-anchor" href="#社交互动的巨大风险-·-the-great-perils-of-social-interaction" aria-label="Permalink to &quot;社交互动的巨大风险 · The Great Perils of Social Interaction&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/01/the-great-perils-of-social-interaction.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/01/the-great-perils-of-social-interaction.html</a> · 2014-01-21</p></blockquote><p>如果有个外星人移民到地球,他会是个社交灾难。</p><p>他会拼尽全力通过观察人类行为来学习,但这不容易——他看到有人向陌生人讨一根烟,他就跑去讨别人一口拿铁。他看到一对情侣在街上接吻,他就跑去试图亲吻街角的警察。他会盯着看。他会把食物弄得整张外星脸上都是。累了的时候,他就直接躺在人行道上。</p><p>我们这位外星移民撑不到一天就会被逮捕。他不会正确地行事,很快就会被强行从社会中移除。</p><p>事情就是这样——有一套错综复杂、成千上万条的社交规则,而我们所有人都对这些规则异常敏感。如果我们不敏感,就会被发配到某处。即便是接近完美也会让你陷入麻烦——你可以把 98% 的规则烂熟于心,但剩下那 2% 会让你落下「粗鲁」「怪异」或「令人毛骨悚然」的名声。</p><p>但试图遵守《社交规则手册》最难的地方在于,这远不是一本完美的手册。它很像《宪法》:</p><ul><li>它带你到某个程度,然后剩下的大部分都留给你自己解读</li><li>有些部分已经过时或考虑不周,亟需一条修正案</li><li>更复杂的是,每个国家、族裔、文化和亚文化都有自己独特版本的《规则手册》</li></ul><p>不幸的是,在社交互动的世界里,没有最高法院来解读棘手的情况,没有立法机构来修订糟糕的规则,也没有国际法来帮忙在各文化之间统一标准。</p><p>那简直就是他妈的蛮荒西部。</p><p>所以欢迎你走进公共场合,但在你出门之前,我先给你撒一点点你即将面对的危险的小样,作为最后的警告——</p><h2 id="与朋友和家人互动的危险" tabindex="-1">与朋友和家人互动的危险 <a class="header-anchor" href="#与朋友和家人互动的危险" aria-label="Permalink to &quot;与朋友和家人互动的危险&quot;">​</a></h2><p>你可能会觉得跟朋友和家人的互动应该属于比较安全的一类,因为那些人使用的《规则手册》版本很可能大体上跟你的一样。问题是,面对最亲近的人,对亲密和自在的期待会给每一次互动施加压力,让它必须顺利,你们共同的历史又常常让事情充满火药味,而且既然这里是八卦和长期记忆存活的舞台,风险也就最高。另外,你多半是个有点尴尬的人,而尴尬的人永远都不安全,不管跟谁在一起。</p><p>跟朋友或家人见面时,事情在还没开始之前就可能变得棘手,你可能面临一场<strong>30 秒问候大战 (30-Second Hello)</strong>:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/hello.png" target="_blank" rel="noreferrer"><img src="'+o+'" alt="Extended Hello"></a></strong></p><p>而就在你如释重负地以为搞定了的时候,你又会发现自己不得不在我们时代最重大的社交挣扎之一中挑一扇门进去——<strong>握手 / 拥抱之毁灭抉择 (The Handshake/Hug Decision of Doom):</strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/handshake.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="handshake"></a></strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/handshake-2.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="Handshake-Hug Mixup"></a></strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/handshake-3.png" target="_blank" rel="noreferrer"><img src="'+p+'" alt="Handshake-Hug Mixup"></a></strong></p><p>我就算活到 90 岁,估计也还是搞不明白这事儿。每个人的规则都不一样,而且完全没有清晰的标准——见我爷爷是握手还是拥抱?朋友的爸爸呢?老朋友呢?新朋友呢?异性熟人呢?共事多年的同事呢?我兄弟姐妹的好朋友,而且我才第二次见?这简直复杂得离谱。</p><p>而且你能选的还不止两种——还有那种高中兄弟式的握手+拍背的傻叉套路,还有那种垂直、松松垮垮的击掌然后甩手时莫名其妙变成弹指头的诡异张力时刻,甚至还有那种简单但把自己看得贼重、毫无反讽意味的碰拳。而且就算你俩都决定拥抱,还得纠结时长、力度、以及这些破事到底谁说了算。</p><p>(顺便说一句,拥抱这个概念本身就挺怪的。我生活中有一大把人,每次打招呼或告别都要紧紧拥抱,但在其他任何场合我都绝不会那么亲密地触碰他们。这真是毫无道理。写《社交规则手册》的那位仁兄压根没认真想过这事儿。)</p><p>反正呢,就在这事儿不能再难的时候,不知道从哪一步开始,社会觉得把 <em>亲吻</em> 加进这套系统是个好主意。亲吻本来在情侣和亲子领域混得好好的,搞不清楚它为什么要掺和进其他任何场合。除非这明确是你的文化传统,18 岁以下没人打招呼时会亲人,但一进入成年人的世界,你就被默认得自己搞明白什么时候该在打招呼时亲人。而且亲吻还有好几种版本——轻轻的脸颊吻、贴脸的空气吻、荒唐至极的两颊各一下仿佛我们是阿拉伯王子的做作表演——每一种都让局面更加复杂,让我们时刻处于那令人闻风丧胆的 <strong>意外嘴对嘴亲吻</strong> 的深渊边缘:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/kiss1.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt="Accidental Mouth Kiss"></a></strong></p><p>熬过打招呼这一关之后,某些密友还会继续表达亲昵,这就带来了更多麻烦,比如 <strong>那个「等等我们要怎么停下来」的肢体接触困境</strong>。我经常最后不得不假装我胳膊有什么天大的紧急事儿要办。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/adjacent-embrace-1.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="adjacent embrace 1"></a></strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/adjacent-embrace-2.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt="adjacent embrace 2"></a></strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/adjacent-embrace-3.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt="adjacent embrace 3"></a></strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/adjacent-embrace-4.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt="adjacent embrace 4"></a></strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/adjacent-embrace-5.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt="adjacent embrace 5"></a></strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/adjacent-embrace-6.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt="adjacent embrace 6"></a></strong></p><p>而这一切,跟**「跟钱有关的歌舞表演」**比起来,都不算什么。最经典的场景是:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/restaurant-1.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt="Fighting over the bill"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/restaurant-2.png" target="_blank" rel="noreferrer"><img src="'+_+'" alt="Fighting over the bill"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/restaurant-31.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt="restaurant 3"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/restaurant-4.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt="Fighting over the bill"></a></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/restaurant-51.png" target="_blank" rel="noreferrer"><img src="'+k+'" alt="restaurant 5"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/restaurant-6.png" target="_blank" rel="noreferrer"><img src="'+y+'" alt="Fighting over the bill"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/restaurant-7.png" target="_blank" rel="noreferrer"><img src="'+z+'" alt="Fighting over the bill"></a></p><p>但朋友之间的「跟钱有关的歌舞表演」可以在任何时间、任何地点突然上演:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/tic-tacs.png" target="_blank" rel="noreferrer"><img src="'+S+'" alt="Fighting over the bill"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/tic-tacs-2.png" target="_blank" rel="noreferrer"><img src="'+A+'" alt="Fighting over the bill"></a></p><p>而且这还不只是交易场合的事。在 22 岁到 40 岁之间的某个节点,和朋友讨论你的收入、房租、大致的财务状况,会从「完全没问题」变成「完全不太行」。我们所有人都得自己摸索出这个过渡该怎么完成。</p><h2 id="和熟人打交道的巨大风险" tabindex="-1">和熟人打交道的巨大风险 <a class="header-anchor" href="#和熟人打交道的巨大风险" aria-label="Permalink to &quot;和熟人打交道的巨大风险&quot;">​</a></h2><p>「熟人 (acquaintance)」就是那种你认识、但社交上不会跟他单独出来玩的人——如果真要一起,也只会是在一大群人里的那种场合。可能是高中同学但从来没做过朋友的,可能是大学里在同一层住过一年的,可能是你朋友的朋友,或者是同事、前同事,但你其实并不太了解他。</p><p>大部分时候你跟朋友在一起,一切都好——尴尬只是偶尔的例外。但跟熟人在一起,<strong>尴尬才是常态</strong>。我有个理论:「acquaintances(熟人)」这个词其实来源于「awkward(尴尬)」,意思是「让你尴尬的那些人」,原本应该拼作「awkwaintances」,后来为了不那么尴尬,才改了拼法。</p><p>问题在于——跟一个人对话有三种方式:</p><p><strong>1) 预先写好的社交小剧本</strong>——你不想跟这人变得更熟,但又怕在他面前直接做自己,就会用这种方式。</p><p><strong>2) 爬坡</strong>——试图更深入地了解某人,或者更新一下彼此的近况。</p><p><strong>3) 正常相处</strong>——接受这段关系当前的状态,单纯享受彼此陪伴中能享受的部分就行。</p><p>一般来说,让互动变尴尬的罪魁祸首就是不真诚。真诚是尴尬的天敌。而跟熟人打交道时,唯一真诚的选项只有 #3——或者,如果你真的想把关系往朋友那边推进一步,那就选 #2。但通常来说,双方都并没有真的想或计划要成为更好的朋友,那「正常相处」就成了熟人互动的关键。可麻烦也就出在这里。大多数人是这么看这三种互动方式的:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/Acquaintance-graph.png" target="_blank" rel="noreferrer"><img src="'+j+'" alt="Acquaintance Interaction"></a></strong></p><p>但这个假设是:你<strong>只能</strong>在熟人面前正常相处。事实并非如此。去年我开始去一位新的理发师那里,惊喜地发现,他不跟我寒暄客套,也不问我生活上的问题,而是直接把我当朋友一样聊天,或者把我拉进他跟另一位理发师的对话里。这么一来,他就替我们俩省掉了典型「理发师-顾客」关系里那种巨大的不真诚感,现在我真的很喜欢去他那儿。他没有按上面那张图来,而是把事情看成三扇门,你可以自己选:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/doors.png" target="_blank" rel="noreferrer"><img src="'+q+'" alt="Acquaintance Interaction"></a></strong></p><p>你并不是<em>必须</em>得跟人闲聊或者假装想认识对方——这两种都是主动选择,你完全可以选择「正常一点」。可惜社交规则手册里根本没写怎么跟熟人保持正常状态,只有一堆章节教你怎么在跟熟人打交道的恐怖时刻里活下来,不管是真心还是假意。我们迫切需要给这本规则手册打个补丁——在补丁出现之前,我跟理发师那种关系将会是稀有物种。</p><p>眼下我们只能忍受<strong>熟人工作陷阱</strong>这种东西。它发生在两个因为环境所迫成了熟人、每天不得不见面的人身上——他们目光短浅地犯了个错误:牺牲了本可以维持的真实非关系的宁静,换来了永远卡在第1类对话里的狗屁循环地狱:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/work-0.png" target="_blank" rel="noreferrer"><img src="'+I+'" alt="Awkward Work Relationship"></a></strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/work-1.png" target="_blank" rel="noreferrer"><img src="'+P+'" alt="Awkward Work Relationship"></a></strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/work-2.png" target="_blank" rel="noreferrer"><img src="'+T+'" alt="Awkward Work Relationship"></a></strong></p><p>**<a href="https://waitbutwhy.com/wp-content/uploads/2014/01/work-3.png" target="_blank" rel="noreferrer"><img src="'+F+'" alt="Awkward Work Relationship"></a><br> **</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/work-4.png" target="_blank" rel="noreferrer"><img src="'+x+'" alt="Awkward Work Relationship"></a></p><p>因为第1类对话涉及大量由社会预先写好的、罐头式的机器人台词,熟人工作陷阱还会让你面临<strong>机器人台词错配</strong>的巨大风险:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/WhatsUp.jpg" target="_blank" rel="noreferrer"><img src="'+W+'" alt="Smalltalk disaster"></a></strong></p><p>更惨的是在公共场合撞见熟人。两个人通常都被潜在的尴尬吓得魂飞魄散,最后表现得像疯子一样。而且如果哪个傻瓜犯了致命错误——问对方最近怎么样——事情还能拖得非常非常久,酿成<strong>永无止境的熟人偶遇</strong>:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/run-in-1.png" target="_blank" rel="noreferrer"><img src="'+G+'" alt="Awkward Social Interaction"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/run-in-2.png" target="_blank" rel="noreferrer"><img src="'+U+'" alt="Awkward Social Interaction"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/run-in-3.png" target="_blank" rel="noreferrer"><img src="'+v+'" alt="Awkward Social Interaction"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/run-in-4.png" target="_blank" rel="noreferrer"><img src="'+H+'" alt="Awkward Social Interaction"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/run-in-4.5.png" target="_blank" rel="noreferrer"><img src="'+R+'" alt="Awkward Social Interaction"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/run-in-5.png" target="_blank" rel="noreferrer"><img src="'+B+'" alt="Awkward Social Interaction"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/run-in-6.png" target="_blank" rel="noreferrer"><img src="'+D+'" alt="Awkward Social Interaction"></a></p><h2 id="与陌生人互动的种种危险" tabindex="-1">与陌生人互动的种种危险 <a class="header-anchor" href="#与陌生人互动的种种危险" aria-label="Permalink to &quot;与陌生人互动的种种危险&quot;">​</a></h2><p>跟陌生人互动,换句话说就是&quot;跟你这个物种的其余成员互动&quot;,而这事儿常常让人浑身不自在。虽然不像前两类那样有什么真金白银的东西被押上桌(除了你的尊严),但陌生人互动能贡献出人生中一些最尴尬的名场面。</p><p>自我介绍这事儿本身就自带尴尬属性,而如果你还不完全确定眼前这个人到底算不算陌生人,那就更是雪上加霜了。让你把自己坑进去的主要方式是——你记不住之前见过谁,这就会导致**「幸会 / 又见面啦」大型翻车现场**:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/see-meet.jpg" target="_blank" rel="noreferrer"><img src="'+M+'" alt="Nice to Meet You"></a></strong></p><p>然后当然还有<strong>人行道方向镜像大泥潭:</strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/walking-direction-1.png" target="_blank" rel="noreferrer"><img src="'+N+'" alt="walking direction 1"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/walking-direction-2.png" target="_blank" rel="noreferrer"><img src="'+$+'" alt="walking direction 2"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/walking-direction-3.png" target="_blank" rel="noreferrer"><img src="'+E+'" alt="walking direction 3"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/walking-direction-4.png" target="_blank" rel="noreferrer"><img src="'+V+'" alt="walking direction 4"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/walking-direction-5.png" target="_blank" rel="noreferrer"><img src="'+C+'" alt="walking direction 5"></a><br><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/walking-direction-6.png" target="_blank" rel="noreferrer"><img src="'+O+'" alt="walking direction 6"></a><br><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/walking-direction-7.png" target="_blank" rel="noreferrer"><img src="'+Z+'" alt="walking direction 7"></a><br><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/walking-direction-8.png" target="_blank" rel="noreferrer"><img src="'+J+'" alt="walking direction 8"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/walking-direction-9.png" target="_blank" rel="noreferrer"><img src="'+K+'" alt="walking direction 9"></a></p><p>《社交规则手册》里最愚蠢、最过时的条款之一就是:尽管附近那位陌生人跟我毫无关系,可只要我吸进了一点花粉,他就必须<strong>开口命令上帝拯救我</strong>。<strong>莫名其妙的打喷嚏对峙</strong>大概是我人生中最尴尬的一件事,尤其因为我是个连环喷嚏选手。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/sneeze-1.png" target="_blank" rel="noreferrer"><img src="'+Y+'" alt="sneeze 1"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/sneeze-2.png" target="_blank" rel="noreferrer"><img src="'+L+'" alt="sneeze 2"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/sneeze-3.png" target="_blank" rel="noreferrer"><img src="'+Q+'" alt="sneeze 3"><br></a><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/sneeze-4.png" target="_blank" rel="noreferrer"><img src="'+X+'" alt="sneeze 4"><br></a><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/sneeze-5.png" target="_blank" rel="noreferrer"><img src="'+tt+'" alt="sneeze 5"><br></a><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/sneeze-6.png" target="_blank" rel="noreferrer"><img src="'+et+'" alt="sneeze 6"><br></a><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/sneeze-7.png" target="_blank" rel="noreferrer"><img src="'+rt+'" alt="sneeze 7"><br></a><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/sneeze-8.png" target="_blank" rel="noreferrer"><img src="'+at+'" alt="sneeze 8"><br></a><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/sneeze-9.png" target="_blank" rel="noreferrer"><img src="'+nt+'" alt="sneeze 9"><br></a><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/sneeze-10.png" target="_blank" rel="noreferrer"><img src="'+ot+'" alt="sneeze 10"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/sneeze-11.png" target="_blank" rel="noreferrer"><img src="'+it+'" alt="sneeze 11"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/sneeze-12.png" target="_blank" rel="noreferrer"><img src="'+st+'" alt="sneeze 12"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/sneeze-13.png" target="_blank" rel="noreferrer"><img src="'+pt+'" alt="sneeze 13"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/sneeze-14.png" target="_blank" rel="noreferrer"><img src="'+gt+'" alt="sneeze 14"></a></p><p>男人在小便池那片战场上也得应付一堆陌生人尴尬。这可能只是我一个人的怪毛病,但每到某个时刻,只要我感受到一点点尿尿的压力、又开始想得太多,我就完全尿不出来了。在一间死寂的洗手间里,旁边站着另一个人在用小便池,通常就足以触发这一切:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/urinal-1.png" target="_blank" rel="noreferrer"><img src="'+lt+'" alt="Urinal Stage-Fright"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/urinal-2.png" target="_blank" rel="noreferrer"><img src="'+ct+'" alt="Urinal Stage-Fright"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/urinal-3.png" target="_blank" rel="noreferrer"><img src="'+ht+'" alt="Urinal Stage-Fright"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/urinal-4.png" target="_blank" rel="noreferrer"><img src="'+mt+'" alt="Urinal Stage-Fright"></a></p><p>在极少数情况下,旁边那位也是个神经兮兮的怪人,那我们就要面临一个可怕的风险——<strong>小便池无声僵局噩梦</strong>:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/urinal-b-1.png" target="_blank" rel="noreferrer"><img src="'+wt+'" alt="Urinal Stage-Fright"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/urinal-b-2.png" target="_blank" rel="noreferrer"><img src="'+bt+'" alt="Urinal Stage-Fright"></a></p><p>考虑到这个世界上到处都是危险,你可能会想,至少和一个还没开化的小肉团互动应该是安全的吧。再想想。在公共场合和陌生人的宝宝互动是件高风险的事——如果他们对你反应良好,你就成了全场最有魅力的人,所有人突然都对你笑,都想嫁给你。过程是这样的:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/baby-1.png" target="_blank" rel="noreferrer"><img src="'+ft+'" alt="baby 1"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/baby-2.png" target="_blank" rel="noreferrer"><img src="'+_t+'" alt="baby 2"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/baby-3.png" target="_blank" rel="noreferrer"><img src="'+ut+'" alt="baby 3"></a></p><p>宝宝表现得像个通情达理的人,一切顺利。但问题是,相当一部分宝宝其实都是混蛋,而你根本没法提前分辨谁是谁。没有什么比一个宝宝对你反应恶劣更能让你瞬间显得、也感觉自己就是个天大的怪胎。当心<strong>混蛋宝宝</strong>:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/baby-4.png" target="_blank" rel="noreferrer"><img src="'+dt+'" alt="baby 4"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/baby-5.png" target="_blank" rel="noreferrer"><img src="'+kt+'" alt="baby 5"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/baby-6.png" target="_blank" rel="noreferrer"><img src="'+yt+'" alt="baby 6"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/baby-7.png" target="_blank" rel="noreferrer"><img src="'+zt+'" alt="baby 7"></a></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/baby-8.png" target="_blank" rel="noreferrer"><img src="'+St+'" alt="baby 8"></a></strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/baby-9.png" target="_blank" rel="noreferrer"><img src="'+At+'" alt="baby 9"></a></strong></p><p>外面的世界真是艰险。而就在你受够了、准备回家避难的时候,你多半会先跟同行的人道别,然后才发现——你们俩接下来要一起踏上一段<strong>告别后同方向共走之旅</strong>:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/goodbye.png" target="_blank" rel="noreferrer"><img src="'+jt+'" alt="Awkward Goodbye"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/goodbye-2.png" target="_blank" rel="noreferrer"><img src="'+qt+'" alt="Awkward Goodbye"></a></p><h2 id="" tabindex="-1"><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/goodbye-3.png" target="_blank" rel="noreferrer"><img src="'+It+'" alt="Awkward Goodbye"></a> <a class="header-anchor" href="#" aria-label="Permalink to &quot;[![Awkward Goodbye](/images/the-great-perils-of-social-interaction/goodbye-3.png)](https://waitbutwhy.com/wp-content/uploads/2014/01/goodbye-3.png)&quot;">​</a></h2><p><strong>如果你喜欢这篇,可以看看这些:</strong></p><p><strong><a href="https://waitbutwhy.com/2015/07/why-im-always-late.html" target="_blank" rel="noreferrer">为什么我总是迟到</a></strong></p><p><strong><a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">拖延症患者为什么会拖延</a></strong></p><h2 id="_30-岁单身男的-10-种类型" tabindex="-1"><strong><a href="https://waitbutwhy.com/2013/10/10-types-of-30-year-old-single-guys.html" target="_blank" rel="noreferrer">30 岁单身男的 10 种类型</a></strong> <a class="header-anchor" href="#_30-岁单身男的-10-种类型" aria-label="Permalink to &quot;**[30 岁单身男的 10 种类型](https://waitbutwhy.com/2013/10/10-types-of-30-year-old-single-guys.html)**&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会发给你。</p><p>想支持 Wait But Why,请访问我们的**<a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a>**。</p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/01/the-great-perils-of-social-interaction.html&amp;description=The%20Great%20Perils%20of%20Social%20Interaction" target="_blank" rel="noreferrer"><img src="'+Pt+'" alt=""></a></p>',121)])])}const Bt=e(Tt,[["render",Ft]]);export{Rt as __pageData,Bt as default};
